  display: flex;\n  align-items: center;\n  justify-content: center;\n  position: relative;\n  cursor: grab;\n  -webkit-user-select: none;\n          user-select: none;\n}\n.vehicle-view[_ngcontent-%COMP%]:active {\n  cursor: grabbing;\n}\n\n.vehicle-image-large[_ngcontent-%COMP%] {\n  width: 100%;\n  height: 100%;\n  object-fit: contain;\n  pointer-events: none;\n  animation: _ngcontent-%COMP%_fadeIn 0.15s ease-in-out;\n}\n\n@keyframes _ngcontent-%COMP%_fadeIn {\n  from {\n    opacity: 0.8;\n  }\n  to {\n    opacity: 1;\n  }\n}\n.rotation-hint[_ngcontent-%COMP%] {\n  font-size: 13px;\n  color: var(--text-muted);\n  margin-top: 20px;\n  text-align: center;\n  margin-bottom: 15px;\n}\n\n\n\n.rotation-progress[_ngcontent-%COMP%] {\n  width: 100%;\n  max-width: 450px;\n  height: 6px;\n  background: rgba(0, 0, 0, 0.1);\n  border-radius: 10px;\n  overflow: hidden;\n}\n\n.progress-bar[_ngcontent-%COMP%] {\n  height: 100%;\n  background: linear-gradient(90deg, var(--primary-gold), var(--primary-gold-dark));\n  transition: width 0.1s ease;\n  border-radius: 10px;\n}\n\n.vehicle-info[_ngcontent-%COMP%] {\n  padding: 50px 40px;\n}\n.vehicle-info[_ngcontent-%COMP%]   h3[_ngcontent-%COMP%] {\n  font-size: 28px;\n  color: var(--dark-primary);\n  margin-bottom: 15px;\n}\n.vehicle-info[_ngcontent-%COMP%]   .vehicle-description[_ngcontent-%COMP%] {\n  color: var(--text-muted);\n  line-height: 1.7;\n  margin-bottom: 30px;\n}\n.vehicle-info[_ngcontent-%COMP%]   .vehicle-features[_ngcontent-%COMP%] {\n  margin-bottom: 30px;\n}\n.vehicle-info[_ngcontent-%COMP%]   .vehicle-features[_ngcontent-%COMP%]   h4[_ngcontent-%COMP%] {\n  font-size: 18px;\n  color: var(--dark-primary);\n  margin-bottom: 15px;\n}\n.vehicle-info[_ngcontent-%COMP%]   .vehicle-features[_ngcontent-%COMP%]   ul[_ngcontent-%COMP%] {\n  list-style: none;\n  padding: 0;\n  margin: 0;\n}\n.vehicle-info[_ngcontent-%COMP%]   .vehicle-features[_ngcontent-%COMP%]   ul[_ngcontent-%COMP%]   li[_ngcontent-%COMP%] {\n  padding: 8p