            &:last-child {
              border-bottom: none;
            }

            .summary-label {
              display: block;
              font-weight: 700;
              color: var(--dark-primary);
              margin-bottom: 8px;
            }

            .summary-value {
              display: block;
              color: var(--text-muted);
              font-size: 18px;
