        .btn {
          margin-bottom: 15px;
        }

        .quote-note {
          font-size: 13px;
          color: rgba(26, 29, 35, 0.7);
          margin: 0;
        }
      }
    }

    /* CTA SECTION */
    .cta-section {
      background: var(--dark-primary);
      text-align: center;
      padding: 80px 0;

      h2 {
        color: var(--text-light);
