  selectVehicle(vehicle: VehicleType) {
    this.selectedVehicle = vehicle;
    this.currentRotation = 0;
    this.selectedEquipment = [];
    this.stopRotation();
  }

  toggleEquipment(item: Equipment) {
    const index = this.selectedEquipment.findIndex(eq => eq.id === item.id);
    if (index > -1) {
      this.selectedEquipment.splice(index, 1);
    } else {
      this.selectedEquipment.push(item);
    }
  }

  isEquipmentSelected(id: string): boolean {
    return this.selectedEquipment.some(eq => eq.id === id);
  }

  // Iniciar rotación continua al mantener presionado
  startRotation(direction: 'left' | 'right') {
    this.stopRotation();
    
    this.rotationInterval = setInterval(() => {
      if (direction === 'left') {
        this.currentRotation = (this.currentRotation + this.rotationSpeed) % 360;
      } else {
        this.currentRotation = (this.currentRotation - this.rotationSpeed + 360) % 360;
      }
      
      // Redondear para mostrar enteros
      this.currentRotation = Math.round(this.currentRotation);
    }, 16); // ~60 FPS
  }

  // Detener rotación
  stopRotation() {
    if (this.rotationInterval) {
      clearInterval(this.rotationInterval);
      this.rotationInterval = null;
    }
  }

  // Iniciar drag
  startDrag(event: MouseEvent | TouchEvent) {
    this.isDragging = true;
    
    if (event instanceof MouseEvent) {
      this.lastDragX = event.clientX;
    } else if (event.touches && event.touches.length > 0) {
      this.lastDragX = event.touches[0].clientX;
    }
  }

  // Manejar drag
  handleDrag(currentX: number) {
    const deltaX = currentX - this.lastDragX;
    this.currentRotation = (this.currentRotation + deltaX * this.dragSensitivity) % 360;
    
    // Normalizar a 0-360
    if (this.currentRotation < 0) {
      this.currentRotation += 360;
    }
    
    this.currentRotation = Math.round(this.currentRotation);
    this.lastDragX = currentX;
  }

  // Obtener imagen más cercana al ángulo actual
  getRotatedImage(): string {
    if (!this.selectedVehicle) return '';

    // Normalizar rotación
    const normalizedRotation = ((this.currentRotation % 360) + 360) % 360;

    // Encontrar la imagen más cercana
    let closestAngle = 0;
    let minDiff = 360;

    [0, 90, 180, 270].forEach(angle => {
      const diff = Math.min(
        Math.abs(normalizedRotation - angle),
        Math.abs(normalizedRotation - angle + 360),
        Math.abs(normalizedRotation - angle - 360)
      );
      
      if (diff < minDiff) {
        minDiff = diff;
        closestAngle = angle;
      }
    });

    return this.selectedVehicle.images[closestAngle];
  }

  requestCustomQuote() {
    const vehicleName = this.selectedVehicle?.name || '';
    const equipmentNames = this.selectedEquipment.map(eq => eq.name).join(', ');
    
    this.router.navigate(['/contacto'], { 
      queryParams: { 
        service: 'proteccion-ejecutiva',
        vehicle: vehicleName,
        equipment: equipmentNames
      } 
    });
  }

  navigateTo(route: string) {
    this.router.navigate([route]);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }

  ngOnDestroy() {
    this.stopRotation();
  }
}
